content:
## Source

{{ source }}

## World

- id: {{ world.id }}
- name: {{ world.name }}
- description: {{ world.description }}
- language: {{ world.language }}

## Simulation

- id: {{ simulation.id }}
- current time: {{ simulation.current_time }}

## User input

{{ user_input }}

## User character id

{{ user_character_id }}

## Accepted actions to commit

{% for entry in coordination_result.accepted_actions %}
accepted:{{ loop.index0 }}:
- actor id: {{ entry.actor_id }}
- original action index: {{ entry.action_index }}
- start offset seconds: {{ entry.start_offset_seconds }}
- end offset seconds: {{ entry.end_offset_seconds }}
- summary: {{ entry.summary }}
- action type: {{ entry.action.type }}
- label: {{ entry.action.label }}
- target ids: {{ entry.action.target_ids }}
- utterance: {{ entry.action.utterance }}
- expected effects: {{ entry.action.expected_effects }}
{% else %}
- none
{% endfor %}

## Coordination status

- status: {{ coordination_result.status }}
- stopped reason: {{ coordination_result.stopped_reason }}

{% if coordination_result.problem %}
Problem:
- type: {{ coordination_result.problem.type }}
- involved actor ids: {{ coordination_result.problem.involved_actor_ids }}
- description: {{ coordination_result.problem.description }}
{% endif %}

## Actors performing accepted actions

{% for entry in actors %}
- actor id: {{ entry.actor.id }}; name: {{ entry.actor.name }}; location id: {{ entry.location.id }}; location: {{ entry.location.name }}; public state: {{ entry.actor.public_state }}; private state: {{ entry.actor.private_state }}; current activity: {{ entry.actor.current_activity.name }}; activity interruptible: {{ entry.actor.current_activity.interruptible }}
  inventory:
{% for item in entry.inventory %}
  - stack id: {{ item.stack_id }}; item id: {{ item.item_id }}; {{ item.name }} x{{ item.quantity }}{% if item.quality %}; quality: {{ item.quality }}{% endif %}; owner id: {{ item.owner_id }}; description: {{ item.description }}
{% else %}
  - none
{% endfor %}
  equipment:
{% for equipment in entry.equipment %}
  - id: {{ equipment.id }}; {{ equipment.name }}; equipped: {{ equipment.equipped }}{% if equipment.equipped_position %}; position: {{ equipment.equipped_position }}{% endif %}; description: {{ equipment.description }}{% if equipment.quality %}; quality: {{ equipment.quality }}{% endif %}
{% else %}
  - none
{% endfor %}
{% else %}
- none
{% endfor %}

## Nearby normal characters

{% for entry in nearby_characters %}
- id: {{ entry.character.id }}; name: {{ entry.character.name }}; location id: {{ entry.location.id }}; location: {{ entry.location.name }}{% if entry.position %}; position: {{ entry.position }}{% endif %}{% if entry.landmark %}; landmark: {{ entry.landmark.name }}{% endif %}; public state: {{ entry.character.public_state }}; current activity: {{ entry.character.current_activity.name }}; description: {{ entry.character.description }}
{% else %}
- none
{% endfor %}

## Nearby background characters

{% for entry in nearby_background_characters %}
- id: {{ entry.character.id }}; name: {{ entry.character.name }}; location id: {{ entry.location.id }}; location: {{ entry.location.name }}{% if entry.position %}; position: {{ entry.position }}{% endif %}{% if entry.landmark %}; landmark: {{ entry.landmark.name }}{% endif %}; description: {{ entry.character.description }}
{% else %}
- none
{% endfor %}

## Nearby item stacks

{% for entry in nearby_items %}
- stack id: {{ entry.stack.id }}; item id: {{ entry.item.id }}; {{ entry.item.name }} x{{ entry.stack.quantity }}{% if entry.stack.quality %}; quality: {{ entry.stack.quality }}{% endif %}; location id: {{ entry.location.id }}; location: {{ entry.location.name }}{% if entry.position %}; position: {{ entry.position }}{% endif %}{% if entry.owner_id %}; owner id: {{ entry.owner_id }}{% endif %}; description: {{ entry.item.description }}
{% else %}
- none
{% endfor %}

## Nearby equipment

{% for entry in nearby_equipment %}
- id: {{ entry.equipment.id }}; {{ entry.equipment.name }}; location id: {{ entry.location.id }}; location: {{ entry.location.name }}{% if entry.position %}; position: {{ entry.position }}{% endif %}{% if entry.owner_id %}; owner id: {{ entry.owner_id }}{% endif %}; description: {{ entry.equipment.description }}{% if entry.equipment.quality %}; quality: {{ entry.equipment.quality }}{% endif %}
{% else %}
- none
{% endfor %}

## Nearby containers

{% for entry in nearby_containers %}
- id: {{ entry.container.id }}; {{ entry.container.name }}; state: {{ entry.container.state }}; location id: {{ entry.location.id }}; location: {{ entry.location.name }}{% if entry.position %}; position: {{ entry.position }}{% endif %}{% if entry.owner_id %}; owner id: {{ entry.owner_id }}{% endif %}; description: {{ entry.container.description }}
{% else %}
- none
{% endfor %}

## Nearby landmarks

{% for landmark in nearby_landmarks %}
- id: {{ landmark.id }}; {{ landmark.name }}; description: {{ landmark.description }}
{% else %}
- none
{% endfor %}
